"use client";

import * as React from "react";
import {
  IconChevronRight,
  IconGift,
  IconArrowUpRight,
  IconArrowDownRight,
  IconCircleMinus,
  IconSparkles,
  IconDiscount2,
  IconReceiptYen,
  IconRosetteDiscountCheck,
} from "@tabler/icons-react";
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  ListCard,
  Badge,
  Tag,
  Button,
  Separator,
  Banner,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  Accordion,
  AccordionItem,
  AccordionTrigger,
  AccordionContent,
  EmptyState,
  formatNumber,
} from "@gunjo/ui";
import { LoyaltyHero } from "./LoyaltyHero";
import {
  MEMBER,
  RANKS,
  COUPONS,
  HISTORY,
  CAMPAIGNS,
  type Coupon,
  type CouponKind,
  type HistoryKind,
} from "./data";

/* ---------------- helpers ---------------- */

const COUPON_ICON: Record<CouponKind, React.ReactNode> = {
  percent: <IconDiscount2 className="size-6 text-primary" />,
  yen: <IconReceiptYen className="size-6 text-primary" />,
  multiplier: <IconSparkles className="size-6 text-warning" />,
};

const HISTORY_META: Record<
  HistoryKind,
  { icon: React.ReactNode; tone: string; sign: string }
> = {
  earn: {
    icon: <IconArrowUpRight className="size-4 text-success-strong" />,
    tone: "text-success-strong",
    sign: "+",
  },
  use: {
    icon: <IconArrowDownRight className="size-4 text-foreground" />,
    tone: "text-foreground",
    sign: "",
  },
  expire: {
    icon: <IconCircleMinus className="size-4 text-muted-foreground" />,
    tone: "text-muted-foreground",
    sign: "",
  },
};

/* ---------------- page ---------------- */

export default function RetailRewardsPage() {
  const [barcodeOpen, setBarcodeOpen] = React.useState(false);
  const [activeCoupon, setActiveCoupon] = React.useState<Coupon | null>(null);
  const [usedCoupons, setUsedCoupons] = React.useState<Set<string>>(new Set());

  const rankIndex = RANKS.findIndex((r) => r.key === MEMBER.currentRank);
  const currentRank = RANKS[rankIndex];
  const nextRank = RANKS[rankIndex + 1];

  const visibleCoupons = COUPONS.filter((c) => !usedCoupons.has(c.id));

  return (
    <main className="mx-auto flex w-full max-w-md flex-col gap-6 px-4 pb-16 pt-4">
      <header className="flex items-center justify-between">
        <div>
          <p className="text-xs text-muted-foreground">ハッピーズ メンバーズ</p>
          <h1 className="text-lg font-bold tracking-tight">マイページ</h1>
        </div>
        <span className="text-xs text-muted-foreground">
          会員No. {MEMBER.memberNo}
        </span>
      </header>

      <LoyaltyHero onShowBarcode={() => setBarcodeOpen(true)} />

      {/* 誕生日特典の告知 */}
      {MEMBER.birthdayCouponActive && (
        <Banner
          variant="warning"
          icon={<IconGift className="size-4" />}
          className="h-auto rounded-lg py-2"
        >
          お誕生日月の特典クーポンが届いています
        </Banner>
      )}

      {/* クーポン */}
      <section aria-labelledby="coupons-heading" className="flex flex-col gap-3">
        <div className="flex items-center justify-between">
          <h2 id="coupons-heading" className="text-base font-bold">
            つかえるクーポン
          </h2>
          <Badge variant="secondary" className="tabular-nums">
            {visibleCoupons.length}件
          </Badge>
        </div>

        {visibleCoupons.length === 0 ? (
          <EmptyState
            title="クーポンはすべて利用済みです"
            description="新しいクーポンが届いたらここに表示されます。"
          />
        ) : (
          <div className="flex flex-col gap-2.5">
            {visibleCoupons.map((c) => (
              <ListCard
                key={c.id}
                onSelect={() => setActiveCoupon(c)}
                severity={c.featured ? "warning" : undefined}
                leading={
                  <span className="flex size-11 items-center justify-center rounded-lg bg-muted">
                    {COUPON_ICON[c.kind]}
                  </span>
                }
                title={
                  <span className="flex items-center gap-2">
                    <span className="text-base font-bold text-primary">
                      {c.headline}
                    </span>
                    {c.featured && (
                      <Badge variant="warning" icon={<IconGift />}>
                        誕生日特典
                      </Badge>
                    )}
                  </span>
                }
                description={
                  <>
                    {c.title}
                    <br />
                    対象: {c.target}
                    {c.condition ? ` / ${c.condition}` : ""}
                  </>
                }
                tags={
                  <Tag
                    variant={c.daysLeft <= 3 ? "destructive" : "outline"}
                    size="sm"
                  >
                    {c.daysLeft <= 3
                      ? `まもなく終了 (〜${c.expires})`
                      : `〜${c.expires}`}
                  </Tag>
                }
              />
            ))}
          </div>
        )}
      </section>

      {/* ポイント履歴 */}
      <section aria-labelledby="history-heading" className="flex flex-col gap-3">
        <h2 id="history-heading" className="text-base font-bold">
          ポイント履歴
        </h2>
        <Tabs defaultValue="all">
          <TabsList className="w-full">
            <TabsTrigger value="all" className="flex-1">
              すべて
            </TabsTrigger>
            <TabsTrigger value="earn" className="flex-1">
              獲得
            </TabsTrigger>
            <TabsTrigger value="use" className="flex-1">
              利用・失効
            </TabsTrigger>
          </TabsList>

          {(
            [
              ["all", HISTORY],
              ["earn", HISTORY.filter((h) => h.kind === "earn")],
              ["use", HISTORY.filter((h) => h.kind !== "earn")],
            ] as const
          ).map(([value, rows]) => (
            <TabsContent key={value} value={value} className="mt-3">
              <div className="flex flex-col gap-2">
                {rows.map((h) => {
                  const m = HISTORY_META[h.kind];
                  return (
                    <ListCard
                      key={h.id}
                      leading={
                        <span className="flex size-9 items-center justify-center rounded-full bg-muted">
                          {m.icon}
                        </span>
                      }
                      title={h.label}
                      description={`${h.date} ・ ${h.detail}`}
                      meta={
                        <span
                          className={`text-sm font-bold tabular-nums ${m.tone}`}
                        >
                          {m.sign}
                          {formatNumber(h.delta)}P
                        </span>
                      }
                      trailing={null}
                    />
                  );
                })}
              </div>
            </TabsContent>
          ))}
        </Tabs>
      </section>

      {/* ランク特典 */}
      <section aria-labelledby="benefits-heading" className="flex flex-col gap-3">
        <h2 id="benefits-heading" className="text-base font-bold">
          ランク特典
        </h2>
        <Card>
          <CardHeader className="p-4 pb-2">
            <div className="flex items-center justify-between">
              <CardTitle as="h3" className="text-base">
                現在: {currentRank.label}会員
              </CardTitle>
              <Badge variant="success">還元率 {currentRank.rate}</Badge>
            </div>
            <CardDescription>
              {currentRank.label}ランクで受けられる特典です
            </CardDescription>
          </CardHeader>
          <CardContent className="p-4 pt-2">
            <ul className="flex flex-col gap-2 text-sm">
              {[
                `ポイント還元率 ${currentRank.rate}`,
                "毎月第2火曜は ポイント2倍",
                "お誕生日月クーポン プレゼント",
                "ゴールド限定セールへのご招待",
              ].map((b) => (
                <li key={b} className="flex items-start gap-2">
                  <IconRosetteDiscountCheck className="mt-0.5 size-4 shrink-0 text-success-strong" />
                  <span>{b}</span>
                </li>
              ))}
            </ul>

            {nextRank && (
              <>
                <Separator className="my-3" />
                <Accordion type="single" collapsible className="border-0">
                  <AccordionItem value="next" className="border-b-0">
                    <AccordionTrigger className="px-0 py-1 hover:no-underline">
                      <span className="flex items-center gap-2 text-sm font-medium">
                        <IconArrowUpRight className="size-4 text-primary" />
                        {nextRank.label}にあがると…
                      </span>
                    </AccordionTrigger>
                    <AccordionContent className="px-0 pb-0">
                      <ul className="flex flex-col gap-2 pt-1 text-sm text-foreground">
                        <li className="flex items-start gap-2">
                          <IconArrowUpRight className="mt-0.5 size-4 shrink-0 text-primary" />
                          還元率が {currentRank.rate} → {nextRank.rate} にアップ
                        </li>
                        <li className="flex items-start gap-2">
                          <IconArrowUpRight className="mt-0.5 size-4 shrink-0 text-primary" />
                          送料無料クーポンを毎月プレゼント
                        </li>
                        <li className="flex items-start gap-2">
                          <IconArrowUpRight className="mt-0.5 size-4 shrink-0 text-primary" />
                          優先カスタマーサポート
                        </li>
                      </ul>
                    </AccordionContent>
                  </AccordionItem>
                </Accordion>
              </>
            )}
          </CardContent>
        </Card>
      </section>

      {/* おすすめキャンペーン */}
      <section
        aria-labelledby="campaign-heading"
        className="flex flex-col gap-3"
      >
        <h2 id="campaign-heading" className="text-base font-bold">
          おすすめキャンペーン
        </h2>
        <div className="flex flex-col gap-2.5">
          {CAMPAIGNS.map((ca) => (
            <Card key={ca.id} className="overflow-hidden">
              <CardContent className="flex items-start gap-3 p-4">
                <span className="flex size-10 shrink-0 items-center justify-center rounded-lg bg-primary-subtle text-primary-subtle-foreground">
                  <IconSparkles className="size-5" />
                </span>
                <div className="min-w-0 flex-1">
                  <div className="flex items-center gap-2">
                    <Badge variant="info">{ca.badge}</Badge>
                    <span className="text-xs text-muted-foreground">
                      {ca.period}
                    </span>
                  </div>
                  <p className="mt-1 font-semibold">{ca.title}</p>
                  <p className="mt-0.5 text-sm text-muted-foreground">
                    {ca.body}
                  </p>
                </div>
                <IconChevronRight className="mt-1 size-5 shrink-0 text-muted-foreground" />
              </CardContent>
            </Card>
          ))}
        </div>
      </section>

      {/* 会員バーコード モーダル */}
      <Dialog open={barcodeOpen} onOpenChange={setBarcodeOpen}>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>会員証バーコード</DialogTitle>
            <DialogDescription>
              レジでこの画面をご提示ください
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col items-center gap-3 rounded-lg border bg-card p-5">
            <Badge variant="success">{currentRank.label}会員</Badge>
            {/* バーコードの簡易表現 — kit に Barcode/会員証 コンポーネントが無いので
                CSS で描画。実機ではバーコード生成ライブラリに差し替える想定。 */}
            <div
              aria-hidden
              className="flex h-20 w-full items-stretch gap-px overflow-hidden rounded bg-white px-2 py-2"
            >
              {MEMBER.barcode
                .repeat(4)
                .split("")
                .map((d, i) => (
                  <span
                    key={i}
                    className="bg-black"
                    style={{
                      width: (Number(d) % 3) + 1,
                      opacity: Number(d) % 2 ? 1 : 0.85,
                    }}
                  />
                ))}
            </div>
            <p className="font-mono text-sm tracking-[0.3em] text-foreground">
              {MEMBER.barcode}
            </p>
            <p className="text-xs text-muted-foreground">
              利用可能ポイント {formatNumber(MEMBER.points)}P
            </p>
          </div>
        </DialogContent>
      </Dialog>

      {/* クーポン利用 確認モーダル */}
      <Dialog
        open={activeCoupon !== null}
        onOpenChange={(open) => !open && setActiveCoupon(null)}
      >
        <DialogContent className="max-w-sm">
          {activeCoupon && (
            <>
              <DialogHeader>
                <DialogTitle className="flex items-center gap-2">
                  <span className="text-primary">{activeCoupon.headline}</span>
                  {activeCoupon.title}
                </DialogTitle>
                <DialogDescription>
                  対象: {activeCoupon.target}
                  {activeCoupon.condition ? ` / ${activeCoupon.condition}` : ""}
                  <br />
                  有効期限: {activeCoupon.expires}
                </DialogDescription>
              </DialogHeader>
              <div className="rounded-lg bg-warning-subtle p-3 text-sm text-warning-subtle-foreground">
                「使う」を押すとクーポンが有効になります。会計時にレジで会員証バーコードをご提示ください。
              </div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  size="lg"
                  className="flex-1"
                  onClick={() => setActiveCoupon(null)}
                >
                  もどる
                </Button>
                <Button
                  variant="primary"
                  size="lg"
                  className="flex-1"
                  onClick={() => {
                    setUsedCoupons((prev) =>
                      new Set(prev).add(activeCoupon.id)
                    );
                    setActiveCoupon(null);
                  }}
                >
                  このクーポンを使う
                </Button>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </main>
  );
}

/**
 * ハッピーズドラッグ メンバーズ — 画面用ダミーデータ。
 * 純データのみ（関数を持たない）。Server / Client どちらからも import 可。
 */

export type RankKey = "regular" | "silver" | "gold" | "platinum";

export interface RankDef {
  key: RankKey;
  /** 表示名 */
  label: string;
  /** ポイント還元率 */
  rate: string;
  /** ランク到達に必要な年間購入額（円） */
  threshold: number;
}

/** 会員ランク定義（年間購入額で判定） */
export const RANKS: RankDef[] = [
  { key: "regular", label: "レギュラー", rate: "1.0%", threshold: 0 },
  { key: "silver", label: "シルバー", rate: "1.5%", threshold: 30_000 },
  { key: "gold", label: "ゴールド", rate: "2.0%", threshold: 80_000 },
  { key: "platinum", label: "プラチナ", rate: "3.0%", threshold: 150_000 },
];

export interface MemberState {
  name: string;
  memberNo: string;
  /** 会員バーコードに使う番号 */
  barcode: string;
  /** ポイント残高 */
  points: number;
  /** 今期 年間購入額（ランク判定の母数） */
  annualSpend: number;
  /** 今期 来店回数 */
  visits: number;
  currentRank: RankKey;
  /** 30日以内に失効予定のポイント */
  expiringPoints: number;
  expiringDate: string;
  /** 誕生日特典の有無 */
  birthdayCouponActive: boolean;
}

export const MEMBER: MemberState = {
  name: "田中 美咲",
  memberNo: "8821-0473-2096",
  barcode: "2882104732096",
  points: 3_480,
  annualSpend: 96_200,
  visits: 34,
  currentRank: "gold",
  expiringPoints: 200,
  expiringDate: "6/30",
  birthdayCouponActive: true,
};

export type CouponKind = "percent" | "yen" | "multiplier";

export interface Coupon {
  id: string;
  kind: CouponKind;
  /** 「20%OFF」「150円引き」「ポイント5倍」など */
  headline: string;
  title: string;
  target: string;
  /** 利用条件 */
  condition?: string;
  expires: string;
  /** 残り日数（期限が近いと警告色に） */
  daysLeft: number;
  /** 誕生日特典など特別枠 */
  featured?: boolean;
}

export const COUPONS: Coupon[] = [
  {
    id: "cp-bday",
    kind: "multiplier",
    headline: "ポイント10倍",
    title: "お誕生日月 特典クーポン",
    target: "全商品",
    condition: "1会計1,000円以上",
    expires: "6/30",
    daysLeft: 3,
    featured: true,
  },
  {
    id: "cp-1",
    kind: "percent",
    headline: "20%OFF",
    title: "化粧品 まとめ買いクーポン",
    target: "スキンケア・メイク用品",
    condition: "3点以上購入で",
    expires: "7/15",
    daysLeft: 18,
  },
  {
    id: "cp-2",
    kind: "yen",
    headline: "150円引き",
    title: "日用品 お買い得クーポン",
    target: "洗剤・紙製品",
    condition: "税込1,500円以上",
    expires: "7/2",
    daysLeft: 5,
  },
  {
    id: "cp-3",
    kind: "multiplier",
    headline: "ポイント5倍",
    title: "週末ボーナスポイント",
    target: "食品・飲料",
    expires: "6/29",
    daysLeft: 2,
  },
];

export type HistoryKind = "earn" | "use" | "expire";

export interface HistoryEntry {
  id: string;
  kind: HistoryKind;
  date: string;
  /** 店舗または事由 */
  label: string;
  detail: string;
  /** 符号つきポイント（獲得 +, 利用/失効 -） */
  delta: number;
}

export const HISTORY: HistoryEntry[] = [
  { id: "h1", kind: "earn", date: "6/25", label: "ハッピーズドラッグ 自由が丘店", detail: "お買い物 ¥4,280", delta: 86 },
  { id: "h2", kind: "use", date: "6/22", label: "ポイント利用", detail: "レジでのお支払い", delta: -500 },
  { id: "h3", kind: "earn", date: "6/22", label: "ハッピーズドラッグ 自由が丘店", detail: "お買い物 ¥2,640", delta: 53 },
  { id: "h4", kind: "earn", date: "6/18", label: "ハッピーズスーパー 中目黒店", detail: "お買い物 ¥6,910 (ポイント5倍)", delta: 691 },
  { id: "h5", kind: "expire", date: "5/31", label: "ポイント失効", detail: "有効期限切れ", delta: -120 },
];

export interface Campaign {
  id: string;
  badge: string;
  title: string;
  period: string;
  body: string;
}

export const CAMPAIGNS: Campaign[] = [
  {
    id: "ca1",
    badge: "ポイントUP",
    title: "毎週日曜は ポイント3倍デー",
    period: "毎週日曜",
    body: "対象店舗でのお買い物がいつでもポイント3倍。アプリ提示でさらに+1倍。",
  },
  {
    id: "ca2",
    badge: "アプリ限定",
    title: "クーポンガチャ 毎日1回",
    period: "〜7/31",
    body: "1日1回引けるクーポンガチャ。最大500円引きが当たるかも。",
  },
];

"use client";

import * as React from "react";
import {
  IconCrown,
  IconBarcode,
  IconAlertTriangle,
  IconChevronRight,
} from "@tabler/icons-react";
import {
  Badge,
  Meter,
  Button,
  formatNumber,
  formatCurrency,
} from "@gunjo/ui";
import { MEMBER, RANKS } from "./data";

/**
 * LoyaltyHero — ポイント残高 / 会員ランク / 次ランクまでの進捗 / 失効警告 をまとめた
 * メンバーズアプリの「自分の今」を映すヒーロー。
 *
 * @gunjo/ui に loyalty / points / tier 用の SUMMARY コンポーネントが存在しないため、
 * このヒーローのシェル（ブランド gradient surface・大きな残高・ランクバッジの並び）は
 * 手書き。中の Meter / Badge / Button は @gunjo/ui を使用。
 */
export function LoyaltyHero({ onShowBarcode }: { onShowBarcode: () => void }) {
  const rankIndex = RANKS.findIndex((r) => r.key === MEMBER.currentRank);
  const currentRank = RANKS[rankIndex];
  const nextRank = RANKS[rankIndex + 1];
  const remaining = nextRank
    ? Math.max(0, nextRank.threshold - MEMBER.annualSpend)
    : 0;

  return (
    <section
      aria-label="ポイントと会員ランク"
      // ブランドの群青 gradient — kit に gradient / brand surface トークンが無いので
      // --gunjo-* atmosphere トークンを arbitrary value で直接利用。
      className="relative overflow-hidden rounded-2xl px-5 pb-5 pt-6 text-white shadow-lg"
      style={{
        backgroundImage:
          "linear-gradient(135deg, hsl(var(--gunjo-deep)) 0%, hsl(var(--gunjo-deeper)) 55%, hsl(var(--gunjo-deepest)) 100%)",
      }}
    >
      {/* 装飾の光 */}
      <div
        aria-hidden
        className="pointer-events-none absolute -right-10 -top-16 h-44 w-44 rounded-full opacity-25 blur-2xl"
        style={{ background: "hsl(var(--gunjo-bright))" }}
      />

      <div className="relative">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <span className="text-sm font-medium text-white/80">
              {MEMBER.name} 様
            </span>
          </div>
          <Badge
            icon={<IconCrown />}
            className="border-0 bg-amber-300/90 text-amber-950"
          >
            {currentRank.label}会員
          </Badge>
        </div>

        {/* ポイント残高 — big number */}
        <div className="mt-4">
          <p className="text-xs font-medium tracking-wide text-white/70">
            利用可能ポイント
          </p>
          <p className="mt-1 flex items-baseline gap-1">
            <span className="text-5xl font-bold tabular-nums tracking-tight">
              {formatNumber(MEMBER.points)}
            </span>
            <span className="text-lg font-medium text-white/80">P</span>
          </p>
          <p className="mt-1 text-xs text-white/70">
            1ポイント = 1円としてお使いいただけます
          </p>
        </div>

        {/* 会員バーコード呼び出し */}
        <Button
          variant="secondary"
          size="lg"
          onClick={onShowBarcode}
          className="mt-4 w-full justify-between bg-white/95 text-foreground hover:bg-white"
        >
          <span className="flex items-center gap-2">
            <IconBarcode className="size-5" />
            会員証バーコードを表示
          </span>
          <IconChevronRight className="size-4 opacity-60" />
        </Button>

        {/* ランクアップ進捗 */}
        <div className="mt-5 rounded-xl bg-white/10 p-4 backdrop-blur-sm">
          {nextRank ? (
            <>
              <div className="mb-2 flex items-baseline justify-between gap-2 text-sm">
                <span className="font-medium text-white">
                  次のランク「{nextRank.label}」まで
                </span>
                <span className="tabular-nums font-semibold text-amber-200">
                  あと {formatCurrency(remaining)}
                </span>
              </div>
              <Meter
                value={MEMBER.annualSpend}
                max={nextRank.threshold}
                tone="warning"
                showValue={false}
                label={`${nextRank.label}までの進捗`}
                className="[&_*]:!text-white"
              />
              <p className="mt-2 text-xs text-white/70">
                年間購入額 {formatCurrency(MEMBER.annualSpend)} ・ 来店{" "}
                {MEMBER.visits}回（{currentRank.label} 還元率{" "}
                {currentRank.rate}）
              </p>
            </>
          ) : (
            <p className="text-sm font-medium text-white">
              最高ランク「{currentRank.label}」を維持中です 🎉
            </p>
          )}
        </div>

        {/* 失効予定の警告 — Banner は h-10 固定で hero 内に入れると窮屈なので
            ここは手書きの注意行（kit に「ヒーロー内インライン警告」枠が無い）。 */}
        {MEMBER.expiringPoints > 0 && (
          <div className="mt-3 flex items-center gap-2 rounded-lg bg-amber-400/15 px-3 py-2 text-sm text-amber-100 ring-1 ring-amber-300/30">
            <IconAlertTriangle className="size-4 shrink-0 text-amber-300" />
            <span>
              <span className="font-semibold tabular-nums">
                {formatNumber(MEMBER.expiringPoints)}P
              </span>{" "}
              が {MEMBER.expiringDate} に失効予定です
            </span>
          </div>
        )}
      </div>
    </section>
  );
}
